#include<bits/stdc++.h>
using namespace std;
int fa[2001];
int find(int x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
void merge(int x,int y)
{
    fa[find(x)]=find(y);
}
bool vis[2001];
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n*2;i++)
    {
        fa[i]=i;
    }
    for(int i=1;i<=m;i++)
    {
        int x,y;
        char op;
        cin>>op>>x>>y;
        if(op=='E')
        {
            merge(x+n,y);
            merge(x,y+n);
        }
        else
        {
            merge(x,y);
        }
    }
    int cnt=0;
    for(int i=1;i<=n;i++)
    {
        if(!vis[find(i)])
        {
            vis[find(i)]=1;
            cnt++;
        }
    }
    printf("%d",cnt);
    return 0;
}
